**Segment Tree:** supports range queries and point/range updates in O(log n).

```python
class SegTree:
    def __init__(self, n):
        self.n = n
        self.tree = [0] * (4*n)     # 4*n space

    def update(self, node, l, r, idx, val):
        if l == r:
            self.tree[node] = val
            return
        mid = (l+r)//2
        if idx <= mid: self.update(2*node, l, mid, idx, val)
        else:          self.update(2*node+1, mid+1, r, idx, val)
        self.tree[node] = self.tree[2*node] + self.tree[2*node+1]

    def query(self, node, l, r, ql, qr):
        if qr < l or r < ql: return 0
        if ql <= l and r <= qr: return self.tree[node]
        mid = (l+r)//2
        return self.query(2*node, l, mid, ql, qr) + \
               self.query(2*node+1, mid+1, r, ql, qr)
```
